// ------------------------------------------------------------
// Helpers
// ------------------------------------------------------------
static SnapStep snapStepFromModifiers(Qt::KeyboardModifiers mods)
{
    if (mods & Qt::ControlModifier) return SnapStep::MM_10;
    if (mods & Qt::ShiftModifier)   return SnapStep::MM_5;
    return SnapStep::MM_1;
}

int WorkspaceView::normalizeMod(int v, int m)
{
    if (m <= 0) return 0;
    const int r = v % m;
    return (r < 0) ? (r + m) : r;
}

static double pointDistanceToSegment(const QPointF& p, const QLineF& seg)
{
    const QPointF a = seg.p1();
    const QPointF b = seg.p2();
    const QPointF ab(b.x() - a.x(), b.y() - a.y());
    const QPointF ap(p.x() - a.x(), p.y() - a.y());

    const double ab2 = (ab.x() * ab.x()) + (ab.y() * ab.y());
    if (ab2 <= 1e-9)
        return QLineF(p, a).length();

    double t = ((ap.x() * ab.x()) + (ap.y() * ab.y())) / ab2;
    if (t < 0.0) t = 0.0;
    if (t > 1.0) t = 1.0;

    const QPointF proj(a.x() + ab.x() * t, a.y() + ab.y() * t);
    return QLineF(p, proj).length();
}

static bool canCollapseGuidePoint(const QPointF& a, const QPointF& b, const QPointF& c)
{
    const QPointF ab(b.x() - a.x(), b.y() - a.y());
    const QPointF bc(c.x() - b.x(), c.y() - b.y());
    const double cross = ab.x() * bc.y() - ab.y() * bc.x();
    const double dot = ab.x() * bc.x() + ab.y() * bc.y();
    return std::abs(cross) <= 1e-6 && dot > 0.0;
}

