static std::int64_t unwrapXAbs(std::int64_t xMod, std::int64_t lastXAbs, std::int64_t L)
{
    if (L <= 0)
        return xMod;

    const std::int64_t k0 = lastXAbs / L;

    std::int64_t best = xMod + k0 * L;
    std::int64_t bestDist = std::llabs(best - lastXAbs);

    for (int dk = -1; dk <= 1; ++dk)
    {
        const std::int64_t candidate = xMod + (k0 + dk) * L;
        const std::int64_t dist = std::llabs(candidate - lastXAbs);

        if (dist < bestDist)
        {
            bestDist = dist;
            best = candidate;
        }
    }

    return best;
}

static bool isDirectionAllowed8(std::int64_t dx, int dy)
{
    if (dx == 0 && dy == 0)
        return false;

    if (dx == 0) return true;
    if (dy == 0) return true;
    if (std::abs(dx) == std::abs(dy))
        return true;

    return false;
}

// ============================================================
// Construction
// ============================================================

WorkspaceView::WorkspaceView(QWidget* parent)
    : QGraphicsView(parent)
{
    m_scene = new WorkspaceScene(this);
    setScene(m_scene);

    m_anim = new Ui::Animate(this);
    connect(m_anim, &Ui::Animate::frameChanged,
            this, [this](std::size_t segIndex, double progress)
            {
                if (!m_scene)
                    return;

                // segIndex = segments COMPLETS valides (0..N)
                const bool animRunning = m_anim && m_anim->running();
                m_scene->setAnimationState(animRunning, segIndex, progress);
                if (viewport())
                    viewport()->update();
            });

    connect(m_anim, &Ui::Animate::finished,
            this, [this]()
            {
                if (m_scene)
                    m_scene->setAnimationState(false, 0, 1.0);
                if (viewport())
                    viewport()->update();
            });

    setAlignment(Qt::AlignLeft | Qt::AlignTop);
    setTransformationAnchor(QGraphicsView::NoAnchor);
    setResizeAnchor(QGraphicsView::NoAnchor);

    setRenderHint(QPainter::Antialiasing, false);
    setViewportUpdateMode(QGraphicsView::FullViewportUpdate);
    setFrameStyle(QFrame::NoFrame);
    setMouseTracking(true);

    setHorizontalScrollBarPolicy(Qt::ScrollBarAlwaysOff);
    setVerticalScrollBarPolicy(Qt::ScrollBarAlwaysOff);

    applyHome();
}

// ============================================================
// Crossings Edit Mode (LK-STRICT)
// ============================================================

void WorkspaceView::enterCrossingEditMode()
{
    if (!m_model || !m_scene)
        return;

    m_crossingEditMode = true;
    emit crossingEditModeChanged(true);
    m_scene->setCrossingOverviewEnabled(true);

    goHome();

    const int n = m_scene->crossingCount();
    if (n <= 0)
    {
        m_activeCrossingIndex = -1;
        m_scene->setActiveCrossingIndex(-1);
        return;
    }

    setActiveCrossingIndex(0, true);

    setCursor(Qt::CrossCursor);

    m_hasPreview = false;
    m_previewValid = false;
    if (m_scene)
        m_scene->hideSnapHalo();
    QToolTip::hideText();
}

void WorkspaceView::exitCrossingEditMode()
{
    m_crossingEditMode = false;
    emit crossingEditModeChanged(false);
    if (m_scene)
        m_scene->setCrossingOverviewEnabled(false);
    m_activeCrossingIndex = -1;

    if (m_scene)
        m_scene->setActiveCrossingIndex(-1);

    unsetCursor();
    QToolTip::hideText();
    if (viewport())
        viewport()->update();
}

void WorkspaceView::goHome()
{
    if (!m_model)
        return;

    m_model->setRibbonOffsetMM(0);
    SnapEngine::setRibbonOffset(m_model->ribbonOffsetMM());
    updateViewTransform();

    m_hasLastSnapXAbs = false;

    if (m_scene)
        m_scene->hideSnapHalo();

    if (viewport())
        viewport()->update();
}

void WorkspaceView::setActiveCrossingIndex(int idx, bool recenter)
{
    if (!m_model || !m_scene)
        return;

    const int n = m_scene->crossingCount();
    if (n <= 0)
        return;

    if (idx < 0)  idx = n - 1;
    if (idx >= n) idx = 0;

    m_activeCrossingIndex = idx;
    m_scene->setActiveCrossingIndex(idx);

    if (recenter)
        ensureActiveCrossingVisibleX();

    if (m_scene)
        m_scene->refreshActiveCrossingTooltipAt(activeCrossingGlobalTooltipPos());

    warpCursorToActiveCrossing();

    if (viewport())
        viewport()->update();
}

QPoint WorkspaceView::activeCrossingGlobalTooltipPos() const
{
    if (!m_scene)
        return QCursor::pos();

    if (m_scene->activeCrossingIndex() < 0)
        return QCursor::pos();

    const QPointF absPos = m_scene->activeCrossingAbsPosMM();
    const QPoint vp = mapFromScene(absPos);
    return viewport()->mapToGlobal(vp);
}

void WorkspaceView::warpCursorToActiveCrossing()
{
    if (!m_crossingEditMode)
        return;

    QCursor::setPos(activeCrossingGlobalTooltipPos());
}

// ============================================================
// Model
// ============================================================

void WorkspaceView::setModel(Model::WorkspaceModel* model)
{
    m_model = model;

    if (m_scene)
        m_scene->setModel(model);

    syncFromModel();
}

void WorkspaceView::syncFromModel()
{
    if (m_model)
    {
        SnapEngine::setRibbonLength(m_model->ribbonLengthMM());
        SnapEngine::setRibbonOffset(m_model->ribbonOffsetMM());
    }

    updateViewTransform();

    if (scene())
        scene()->update();
    if (viewport())
        viewport()->update();

    m_hasPreview = false;
    m_hasLastSnapXAbs = false;
    m_lastSnapXAbs = 0;
}

void WorkspaceView::setReadOnlyValidated(bool enabled)
{
    m_readOnlyValidated = enabled;

    if (enabled)
    {
        if (m_crossingEditMode)
            exitCrossingEditMode();

        m_hasPreview = false;
        m_previewValid = false;

        if (m_scene)
            m_scene->hideSnapHalo();
    }

    if (viewport())
        viewport()->update();
}

void WorkspaceView::copyModelGeometryToSketch()
{
    if (!m_model)
        return;

    m_sketchPoints.clear();
    m_sketchSegments.clear();
    m_sketchGuidePaths.clear();
    m_sketchHasAnchor = false;
    m_hasPreviousSketchAnchor = false;
    m_sketchBreak = false;
    clearSketchSelection();
    clearSketchHistory();
    m_hasSketchClipboard = false;
    m_sketchClipboardSegments.clear();
    m_hasLastSketchCursor = false;

    const auto& topo = m_model->topologySnapshot();

    for (const auto& rope : topo.ropes)
    {
        if (rope.points.empty())
            continue;

        std::vector<QPointF> guidePath;
        guidePath.reserve(rope.points.size());
        for (const auto& pt : rope.points)
        {
            const QPointF p(static_cast<double>(pt.xAbs),
                            static_cast<double>(pt.y));

            if (guidePath.size() >= 2
                && canCollapseGuidePoint(guidePath[guidePath.size() - 2],
                                         guidePath.back(),
                                         p))
            {
                guidePath.back() = p;
            }
            else
            {
                guidePath.push_back(p);
            }
        }

        if (guidePath.size() >= 2)
            m_sketchGuidePaths.push_back(std::move(guidePath));
    }

    if (!m_sketchGuidePaths.empty())
        rebuildSketchOverlayFromGuidePaths();

    if (m_sketchSegments.empty())
    {
        const auto& segs = m_model->segments();
        for (const auto& seg : segs)
        {
            m_sketchSegments.push_back(seg);
            m_sketchPoints.push_back(seg.p1());
            m_sketchPoints.push_back(seg.p2());
        }
    }

    const int ribbonLength = m_model->ribbonLengthMM();
    const int ribbonOffset = m_model->ribbonOffsetMM();

    m_model->clear();
    m_model->setRibbonLengthMM(ribbonLength);
    m_model->setRibbonOffsetMM(ribbonOffset);

    syncFromModel();
    setReadOnlyValidated(false);
    enterTracingMode();
}

void WorkspaceView::clearSketchOverlay()
{
    m_sketchPoints.clear();
    m_sketchSegments.clear();
    m_sketchGuidePaths.clear();
    m_sketchHasAnchor = false;
    m_hasPreviousSketchAnchor = false;
    m_sketchBreak = false;

    clearSketchSelection();
    clearSketchHistory();
    m_hasSketchClipboard = false;
    m_sketchClipboardSegments.clear();
    m_hasLastSketchCursor = false;

    m_hasPreview = false;
    m_previewValid = false;

    if (m_scene)
        m_scene->hideSnapHalo();

    if (viewport())
        viewport()->update();
}

void WorkspaceView::triggerUndo()
{
    if (m_readOnlyValidated || !m_model)
        return;

    if (m_sketchMode)
    {
        if (undoSketch() && viewport())
            viewport()->update();
        return;
    }

    if (m_model->canUndo())
    {
        m_model->undo();
        if (m_scene)
            m_scene->update();
        if (viewport())
            viewport()->update();
    }
}

void WorkspaceView::triggerRedo()
{
    if (m_readOnlyValidated || !m_model)
        return;

    if (m_sketchMode)
    {
        if (redoSketch() && viewport())
            viewport()->update();
        return;
    }

    if (m_model->canRedo())
    {
        m_model->redo();
        if (m_scene)
            m_scene->update();
        if (viewport())
            viewport()->update();
    }
}

void WorkspaceView::rotateSelectionRight45()
{
    if (m_readOnlyValidated || !m_sketchMode || m_sketchSegments.empty() || m_sketchSelectedSegmentIndices.empty())
        return;

    if (m_sketchTransforming)
        finishSketchTransformDrag(m_sketchTransformLastMM);

    std::vector<bool> selected(m_sketchSegments.size(), false);
    std::vector<int> indices;
    indices.reserve(m_sketchSelectedSegmentIndices.size());

    for (const int idx : m_sketchSelectedSegmentIndices)
    {
        if (idx < 0 || idx >= static_cast<int>(m_sketchSegments.size()))
            continue;

        if (selected[static_cast<std::size_t>(idx)])
            continue;

        selected[static_cast<std::size_t>(idx)] = true;
        indices.push_back(idx);
    }

    if (indices.empty())
        return;

    double minX = std::numeric_limits<double>::max();
    double minY = std::numeric_limits<double>::max();
    double maxX = -std::numeric_limits<double>::max();
    double maxY = -std::numeric_limits<double>::max();

    for (const int idx : indices)
    {
        const QLineF& seg = m_sketchSegments[static_cast<std::size_t>(idx)];
        minX = std::min(minX, std::min(seg.p1().x(), seg.p2().x()));
        minY = std::min(minY, std::min(seg.p1().y(), seg.p2().y()));
        maxX = std::max(maxX, std::max(seg.p1().x(), seg.p2().x()));
        maxY = std::max(maxY, std::max(seg.p1().y(), seg.p2().y()));
    }

    if (!std::isfinite(minX) || !std::isfinite(minY) || !std::isfinite(maxX) || !std::isfinite(maxY))
        return;

    const QPointF center((minX + maxX) * 0.5, (minY + maxY) * 0.5);
    constexpr double kCos45 = 0.7071067811865475;
    constexpr double kSin45 = -0.7071067811865475; // clockwise

    auto rotatePoint = [&](const QPointF& p) -> QPointF {
        const double dx = p.x() - center.x();
        const double dy = p.y() - center.y();

        const double rx = (dx * kCos45) - (dy * kSin45);
        const double ry = (dx * kSin45) + (dy * kCos45);

        return QPointF(static_cast<double>(std::llround(center.x() + rx)),
                       static_cast<double>(std::llround(center.y() + ry)));
    };

    pushSketchUndoSnapshot();

    for (const int idx : indices)
    {
        const QLineF seg = m_sketchSegments[static_cast<std::size_t>(idx)];
        m_sketchSegments[static_cast<std::size_t>(idx)] = QLineF(rotatePoint(seg.p1()), rotatePoint(seg.p2()));
    }

    m_sketchSelectedSegmentIndices = indices;

    minX = std::numeric_limits<double>::max();
    minY = std::numeric_limits<double>::max();
    maxX = -std::numeric_limits<double>::max();
    maxY = -std::numeric_limits<double>::max();

    for (const int idx : indices)
    {
        const QLineF& seg = m_sketchSegments[static_cast<std::size_t>(idx)];
        minX = std::min(minX, std::min(seg.p1().x(), seg.p2().x()));
        minY = std::min(minY, std::min(seg.p1().y(), seg.p2().y()));
        maxX = std::max(maxX, std::max(seg.p1().x(), seg.p2().x()));
        maxY = std::max(maxY, std::max(seg.p1().y(), seg.p2().y()));
    }

    m_hasSketchSelectionRect = true;
    m_sketchSelectionStartMM = QPointF(minX, minY);
    m_sketchSelectionEndMM = QPointF(maxX, maxY);

    rebuildSketchPointsFromSegments();
    m_hasPreview = false;
    m_previewValid = false;

    if (viewport())
        viewport()->update();
}

void WorkspaceView::invertSelectionDirection()
{
    if (m_readOnlyValidated || !m_sketchMode || m_sketchSegments.empty() || m_sketchSelectedSegmentIndices.empty())
        return;

    if (m_sketchTransforming)
        finishSketchTransformDrag(m_sketchTransformLastMM);

    std::vector<bool> selected(m_sketchSegments.size(), false);
    std::vector<int> indices;
    indices.reserve(m_sketchSelectedSegmentIndices.size());

    for (const int idx : m_sketchSelectedSegmentIndices)
    {
        if (idx < 0 || idx >= static_cast<int>(m_sketchSegments.size()))
            continue;

        if (selected[static_cast<std::size_t>(idx)])
            continue;

        selected[static_cast<std::size_t>(idx)] = true;
        indices.push_back(idx);
    }

    if (indices.empty())
        return;

    double minX = std::numeric_limits<double>::max();
    double minY = std::numeric_limits<double>::max();
    double maxX = -std::numeric_limits<double>::max();
    double maxY = -std::numeric_limits<double>::max();

    for (const int idx : indices)
    {
        const QLineF& seg = m_sketchSegments[static_cast<std::size_t>(idx)];
        minX = std::min(minX, std::min(seg.p1().x(), seg.p2().x()));
        minY = std::min(minY, std::min(seg.p1().y(), seg.p2().y()));
        maxX = std::max(maxX, std::max(seg.p1().x(), seg.p2().x()));
        maxY = std::max(maxY, std::max(seg.p1().y(), seg.p2().y()));
    }

    if (!std::isfinite(minX) || !std::isfinite(minY) || !std::isfinite(maxX) || !std::isfinite(maxY))
        return;

    const double centerX = (minX + maxX) * 0.5;

    auto mirrorPoint = [&](const QPointF& p) -> QPointF {
        const double mx = (2.0 * centerX) - p.x();
        return QPointF(static_cast<double>(std::llround(mx)),
                       static_cast<double>(std::llround(p.y())));
    };

    pushSketchUndoSnapshot();

    for (const int idx : indices)
    {
        const QLineF seg = m_sketchSegments[static_cast<std::size_t>(idx)];
        m_sketchSegments[static_cast<std::size_t>(idx)] = QLineF(mirrorPoint(seg.p2()), mirrorPoint(seg.p1()));
    }

    m_sketchSelectedSegmentIndices = indices;
    m_hasSketchSelectionRect = true;
    m_sketchSelectionStartMM = QPointF(minX, minY);
    m_sketchSelectionEndMM = QPointF(maxX, maxY);
    updateSketchSelectionFromRect();

    rebuildSketchPointsFromSegments();
    m_hasPreview = false;
    m_previewValid = false;

    if (viewport())
        viewport()->update();
}

WorkspaceView::SketchSnapshot WorkspaceView::captureSketchSnapshot() const
{
    SketchSnapshot snapshot;
    snapshot.segments = m_sketchSegments;
    snapshot.points = m_sketchPoints;
    snapshot.hasAnchor = m_sketchHasAnchor;
    snapshot.anchor = m_sketchAnchorMM;
    snapshot.hasPreviousAnchor = m_hasPreviousSketchAnchor;
    snapshot.previousAnchor = m_previousSketchAnchorMM;
    snapshot.sketchBreak = m_sketchBreak;
    return snapshot;
}

void WorkspaceView::restoreSketchSnapshot(const SketchSnapshot& snapshot)
{
    m_sketchSegments = snapshot.segments;
    m_sketchPoints = snapshot.points;
    m_sketchHasAnchor = snapshot.hasAnchor;
    m_sketchAnchorMM = snapshot.anchor;
    m_hasPreviousSketchAnchor = snapshot.hasPreviousAnchor;
    m_previousSketchAnchorMM = snapshot.previousAnchor;
    m_sketchBreak = snapshot.sketchBreak;

    m_hasPreview = false;
    m_previewValid = false;
    clearSketchSelection();
}

void WorkspaceView::pushSketchUndoSnapshot()
{
    m_sketchUndoStack.push_back(captureSketchSnapshot());
    m_sketchRedoStack.clear();
}

bool WorkspaceView::undoSketch()
{
    if (m_sketchUndoStack.empty())
        return false;

    m_sketchRedoStack.push_back(captureSketchSnapshot());
    const SketchSnapshot snapshot = m_sketchUndoStack.back();
    m_sketchUndoStack.pop_back();
    restoreSketchSnapshot(snapshot);
    return true;
}

bool WorkspaceView::redoSketch()
{
    if (m_sketchRedoStack.empty())
        return false;

    m_sketchUndoStack.push_back(captureSketchSnapshot());
    const SketchSnapshot snapshot = m_sketchRedoStack.back();
    m_sketchRedoStack.pop_back();
    restoreSketchSnapshot(snapshot);
    return true;
}

void WorkspaceView::clearSketchHistory()
{
    m_sketchUndoStack.clear();
    m_sketchRedoStack.clear();
}

void WorkspaceView::clearSketchSelection()
{
    m_sketchSelecting = false;
    m_hasSketchSelectionRect = false;
    m_sketchSelectedSegmentIndices.clear();
    cancelSketchTransformDrag();
}

QRectF WorkspaceView::currentSketchSelectionRectMM() const
{
    return QRectF(m_sketchSelectionStartMM, m_sketchSelectionEndMM).normalized();
}

void WorkspaceView::updateSketchSelectionFromRect()
{
    m_sketchSelectedSegmentIndices.clear();

    if (!m_hasSketchSelectionRect)
        return;

    const QRectF rect = currentSketchSelectionRectMM();
    if (rect.width() <= 0.0 && rect.height() <= 0.0)
        return;

    for (std::size_t i = 0; i < m_sketchSegments.size(); ++i)
    {
        const QLineF& seg = m_sketchSegments[i];
        const QRectF bb(seg.p1(), seg.p2());
        const QRectF nbb = bb.normalized();

        const bool selected = rect.contains(seg.p1())
                           || rect.contains(seg.p2())
                           || rect.intersects(nbb);

        if (selected)
            m_sketchSelectedSegmentIndices.push_back(static_cast<int>(i));
    }
}

bool WorkspaceView::copySketchSelectionToClipboard()
{
    if (m_sketchSelectedSegmentIndices.empty())
        return false;

    double minX = std::numeric_limits<double>::max();
    double minY = std::numeric_limits<double>::max();

    for (const int idx : m_sketchSelectedSegmentIndices)
    {
        if (idx < 0 || idx >= static_cast<int>(m_sketchSegments.size()))
            continue;

        const QLineF& seg = m_sketchSegments[static_cast<std::size_t>(idx)];
        minX = std::min(minX, std::min(seg.p1().x(), seg.p2().x()));
        minY = std::min(minY, std::min(seg.p1().y(), seg.p2().y()));
    }

    if (!std::isfinite(minX) || !std::isfinite(minY))
        return false;

    m_sketchClipboardOriginMM = QPointF(minX, minY);
    m_sketchClipboardSegments.clear();

    for (const int idx : m_sketchSelectedSegmentIndices)
    {
        if (idx < 0 || idx >= static_cast<int>(m_sketchSegments.size()))
            continue;

        const QLineF& seg = m_sketchSegments[static_cast<std::size_t>(idx)];
        const QPointF p1 = seg.p1() - m_sketchClipboardOriginMM;
        const QPointF p2 = seg.p2() - m_sketchClipboardOriginMM;
        m_sketchClipboardSegments.emplace_back(p1, p2);
    }

    m_hasSketchClipboard = !m_sketchClipboardSegments.empty();
    return m_hasSketchClipboard;
}

bool WorkspaceView::pasteSketchClipboardAt(const QPointF& targetAbsMM)
{
    if (!m_hasSketchClipboard || m_sketchClipboardSegments.empty())
        return false;

    pushSketchUndoSnapshot();
    clearSketchSelection();

    for (const QLineF& relSeg : m_sketchClipboardSegments)
    {
        const QPointF p1 = targetAbsMM + relSeg.p1();
        const QPointF p2 = targetAbsMM + relSeg.p2();

        m_sketchSegments.emplace_back(p1, p2);
        m_sketchPoints.push_back(p1);
        m_sketchPoints.push_back(p2);
    }

    m_hasPreview = false;
    m_previewValid = false;

    if (viewport())
        viewport()->update();

    return true;
}

bool WorkspaceView::deleteSketchSelection()
{
    if (m_sketchSelectedSegmentIndices.empty() || m_sketchSegments.empty())
        return false;

    std::vector<bool> selected(m_sketchSegments.size(), false);
    int selectedCount = 0;

    for (const int idx : m_sketchSelectedSegmentIndices)
    {
        if (idx < 0 || idx >= static_cast<int>(m_sketchSegments.size()))
            continue;

        if (!selected[static_cast<std::size_t>(idx)])
        {
            selected[static_cast<std::size_t>(idx)] = true;
            ++selectedCount;
        }
    }

    if (selectedCount <= 0)
        return false;

    pushSketchUndoSnapshot();

    std::vector<QLineF> kept;
    kept.reserve(m_sketchSegments.size() - static_cast<std::size_t>(selectedCount));

    for (std::size_t i = 0; i < m_sketchSegments.size(); ++i)
    {
        if (!selected[i])
            kept.push_back(m_sketchSegments[i]);
    }

    m_sketchSegments = std::move(kept);
    rebuildSketchPointsFromSegments();
    clearSketchSelection();

    m_hasPreview = false;
    m_previewValid = false;

    if (viewport())
        viewport()->update();

    return true;
}
bool WorkspaceView::hasSketchSelectionAt(const QPointF& absMM) const
{
    if (m_sketchSelectedSegmentIndices.empty() || m_sketchSegments.empty())
        return false;

    if (m_hasSketchSelectionRect)
    {
        const QRectF rect = currentSketchSelectionRectMM().adjusted(-0.5, -0.5, 0.5, 0.5);
        if (rect.contains(absMM))
            return true;
    }

    constexpr double kPickTolMM = 1.5;

    for (const int idx : m_sketchSelectedSegmentIndices)
    {
        if (idx < 0 || idx >= static_cast<int>(m_sketchSegments.size()))
            continue;

        if (pointDistanceToSegment(absMM, m_sketchSegments[static_cast<std::size_t>(idx)]) <= kPickTolMM)
            return true;
    }

    return false;
}

bool WorkspaceView::beginSketchTransformDrag(const QPointF& startAbsMM, bool copyMode)
{
    if (m_sketchSelectedSegmentIndices.empty() || m_sketchSegments.empty())
        return false;

    std::vector<bool> selected(m_sketchSegments.size(), false);
    m_sketchTransformIndices.clear();
    m_sketchTransformSourceSegments.clear();

    for (const int idx : m_sketchSelectedSegmentIndices)
    {
        if (idx < 0 || idx >= static_cast<int>(m_sketchSegments.size()))
            continue;

        if (selected[static_cast<std::size_t>(idx)])
            continue;

        selected[static_cast<std::size_t>(idx)] = true;
        m_sketchTransformIndices.push_back(idx);
        m_sketchTransformSourceSegments.push_back(m_sketchSegments[static_cast<std::size_t>(idx)]);
    }

    if (m_sketchTransformIndices.empty())
        return false;

    m_sketchTransformBaseSegments = m_sketchSegments;
    m_sketchTransforming = true;
    m_sketchTransformCopy = copyMode;
    m_sketchTransformStartMM = startAbsMM;
    m_sketchTransformLastMM = startAbsMM;
    m_sketchTransformHadRect = m_hasSketchSelectionRect;
    m_sketchTransformRectStartMM = m_sketchSelectionStartMM;
    m_sketchTransformRectEndMM = m_sketchSelectionEndMM;

    pushSketchUndoSnapshot();
    m_sketchTransformUndoPrimed = true;

    m_hasPreview = false;
    m_previewValid = false;
    return true;
}

void WorkspaceView::updateSketchTransformDrag(const QPointF& currentAbsMM)
{
    if (!m_sketchTransforming)
        return;

    m_sketchTransformLastMM = currentAbsMM;
    const QPointF delta = currentAbsMM - m_sketchTransformStartMM;

    m_sketchSegments = m_sketchTransformBaseSegments;

    if (m_sketchTransformCopy)
    {
        std::vector<int> copiedSelection;
        copiedSelection.reserve(m_sketchTransformSourceSegments.size());

        for (const QLineF& src : m_sketchTransformSourceSegments)
        {
            const QLineF moved(src.p1() + delta, src.p2() + delta);
            copiedSelection.push_back(static_cast<int>(m_sketchSegments.size()));
            m_sketchSegments.push_back(moved);
        }

        m_sketchSelectedSegmentIndices = std::move(copiedSelection);
    }
    else
    {
        for (std::size_t i = 0; i < m_sketchTransformIndices.size() && i < m_sketchTransformSourceSegments.size(); ++i)
        {
            const int idx = m_sketchTransformIndices[i];
            if (idx < 0 || idx >= static_cast<int>(m_sketchSegments.size()))
                continue;

            const QLineF& src = m_sketchTransformSourceSegments[i];
            m_sketchSegments[static_cast<std::size_t>(idx)] = QLineF(src.p1() + delta, src.p2() + delta);
        }

        m_sketchSelectedSegmentIndices = m_sketchTransformIndices;
    }

    if (m_sketchTransformHadRect)
    {
        m_hasSketchSelectionRect = true;
        m_sketchSelectionStartMM = m_sketchTransformRectStartMM + delta;
        m_sketchSelectionEndMM = m_sketchTransformRectEndMM + delta;
    }

    rebuildSketchPointsFromSegments();
    m_hasPreview = false;
    m_previewValid = false;
}

void WorkspaceView::finishSketchTransformDrag(const QPointF& endAbsMM)
{
    if (!m_sketchTransforming)
        return;

    updateSketchTransformDrag(endAbsMM);

    const QPointF delta = endAbsMM - m_sketchTransformStartMM;
    const bool moved = (std::abs(delta.x()) > 0.001) || (std::abs(delta.y()) > 0.001);

    if (!moved)
    {
        m_sketchSegments = m_sketchTransformBaseSegments;
        m_sketchSelectedSegmentIndices = m_sketchTransformIndices;

        if (m_sketchTransformHadRect)
        {
            m_hasSketchSelectionRect = true;
            m_sketchSelectionStartMM = m_sketchTransformRectStartMM;
            m_sketchSelectionEndMM = m_sketchTransformRectEndMM;
            updateSketchSelectionFromRect();
        }

        rebuildSketchPointsFromSegments();

        if (m_sketchTransformUndoPrimed && !m_sketchUndoStack.empty())
            m_sketchUndoStack.pop_back();
    }

    cancelSketchTransformDrag();

    if (viewport())
        viewport()->update();
}

void WorkspaceView::cancelSketchTransformDrag()
{
    m_sketchTransforming = false;
    m_sketchTransformCopy = false;
    m_sketchTransformUndoPrimed = false;
    m_sketchTransformHadRect = false;
    m_sketchTransformIndices.clear();
    m_sketchTransformSourceSegments.clear();
    m_sketchTransformBaseSegments.clear();
}
void WorkspaceView::rebuildSketchPointsFromSegments()
{
    m_sketchPoints.clear();

    for (const QLineF& seg : m_sketchSegments)
    {
        m_sketchPoints.push_back(seg.p1());
        m_sketchPoints.push_back(seg.p2());
    }

    if (m_sketchHasAnchor)
        m_sketchPoints.push_back(m_sketchAnchorMM);
}

void WorkspaceView::rebuildSketchOverlayFromGuidePaths()
{
    m_sketchSegments.clear();
    m_sketchPoints.clear();

    for (const auto& path : m_sketchGuidePaths)
    {
        if (path.size() < 2)
            continue;

        for (std::size_t i = 0; i + 1 < path.size(); ++i)
        {
            m_sketchSegments.emplace_back(path[i], path[i + 1]);
            m_sketchPoints.push_back(path[i]);
            m_sketchPoints.push_back(path[i + 1]);
        }
    }

    if (m_sketchHasAnchor)
        m_sketchPoints.push_back(m_sketchAnchorMM);
}

bool WorkspaceView::resolveSketchPointFromDisplay(const QPointF& clickedDisplayAbsMM,
                                                  QPointF* resolvedAbsMM) const
{
    if (!resolvedAbsMM || !m_model || m_sketchPoints.empty())
        return false;

    const int L = m_model->ribbonLengthMM();
    if (L <= 0)
        return false;

    const double clickTol = 3.0;

    bool hasCandidate = false;
    double bestDistance = std::numeric_limits<double>::max();
    QPointF bestAbs;

    for (const QPointF& pointAbs : m_sketchPoints)
    {
        const std::int64_t k = static_cast<std::int64_t>(std::llround(
            (clickedDisplayAbsMM.x() - pointAbs.x()) / static_cast<double>(L)));
        const QPointF candidateAbs(pointAbs.x() + static_cast<double>(k * L),
                                   pointAbs.y());
        const double distance = QLineF(candidateAbs, clickedDisplayAbsMM).length();

        if (distance <= clickTol && distance < bestDistance)
        {
            bestDistance = distance;
            bestAbs = candidateAbs;
            hasCandidate = true;
        }
    }

    if (!hasCandidate)
        return false;

    *resolvedAbsMM = bestAbs;
    return true;
}

bool WorkspaceView::consumeGuidePathByTrace(const QLineF& tracedAbsSegment)
{
    if (m_sketchGuidePaths.empty())
        return false;

    const QPointF traceStart = tracedAbsSegment.p1();
    const QPointF traceEnd = tracedAbsSegment.p2();
    const double tol = 0.5;

    auto samePoint = [tol](const QPointF& a, const QPointF& b) {
        return std::abs(a.x() - b.x()) <= tol
            && std::abs(a.y() - b.y()) <= tol;
    };

    auto keepIfSegmented = [](const std::vector<QPointF>& path,
                              std::vector<std::vector<QPointF>>* out) {
        if (path.size() >= 2)
            out->push_back(path);
    };

    for (std::size_t pathIndex = 0; pathIndex < m_sketchGuidePaths.size(); ++pathIndex)
    {
        const auto& path = m_sketchGuidePaths[pathIndex];
        if (path.size() < 2)
            continue;

        for (std::size_t i = 0; i < path.size(); ++i)
        {
            if (!samePoint(path[i], traceStart))
                continue;

            for (std::size_t j = 0; j < path.size(); ++j)
            {
                if (i == j || !samePoint(path[j], traceEnd))
                    continue;

                const std::size_t lo = std::min(i, j);
                const std::size_t hi = std::max(i, j);

                std::vector<std::vector<QPointF>> rebuilt;
                rebuilt.reserve(m_sketchGuidePaths.size() + 1);

                for (std::size_t other = 0; other < m_sketchGuidePaths.size(); ++other)
                {
                    if (other != pathIndex)
                        rebuilt.push_back(m_sketchGuidePaths[other]);
                }

                std::vector<QPointF> prefix(path.begin(), path.begin() + static_cast<std::ptrdiff_t>(lo + 1));
                std::vector<QPointF> suffix(path.begin() + static_cast<std::ptrdiff_t>(hi), path.end());
                keepIfSegmented(prefix, &rebuilt);
                keepIfSegmented(suffix, &rebuilt);

                m_sketchGuidePaths = std::move(rebuilt);
                rebuildSketchOverlayFromGuidePaths();
                clearSketchSelection();

                if (viewport())
                    viewport()->update();

                return true;
            }
        }
    }

    return false;
}

static bool resolveWrappedXForAllowedDirection(std::int64_t xMod,
                                               std::int64_t currentXAbs,
                                               int dy,
                                               std::int64_t L,
                                               std::int64_t* resolvedXAbs)
{
    if (!resolvedXAbs)
        return false;

    if (L <= 0)
    {
        *resolvedXAbs = xMod;
        return true;
    }

    const std::int64_t k0 = currentXAbs / L;
    bool hasCandidate = false;
    std::int64_t bestCandidate = xMod + k0 * L;
    std::int64_t bestDistance = std::numeric_limits<std::int64_t>::max();

    for (int dk = -2; dk <= 2; ++dk)
    {
        const std::int64_t candidate = xMod + (k0 + dk) * L;
        const std::int64_t dx = candidate - currentXAbs;
        if (!isDirectionAllowed8(dx, dy))
            continue;

        const std::int64_t distance = std::llabs(dx);
        if (!hasCandidate || distance < bestDistance)
        {
            bestCandidate = candidate;
            bestDistance = distance;
            hasCandidate = true;
        }
    }

    if (!hasCandidate)
        return false;

    *resolvedXAbs = bestCandidate;
    return true;
}

static QPointF shiftPointToVisibleCopy(const QPointF& absPoint,
                                       double referenceX,
                                       double L)
{
    if (L <= 0.0)
        return absPoint;

    const std::int64_t k = static_cast<std::int64_t>(std::llround(
        (referenceX - absPoint.x()) / L));
    return QPointF(absPoint.x() + static_cast<double>(k) * L,
                   absPoint.y());
}

bool WorkspaceView::resolveConnectedSketchEndpoint(const QPointF& currentAbsMM,
                                                   const QPointF& clickedDisplayAbsMM,
                                                   QPointF* resolvedAbsMM,
                                                   const QPointF* previousAbsMM) const
{
    if (!resolvedAbsMM || !m_model || m_sketchSegments.empty())
        return false;

    const int L = m_model->ribbonLengthMM();
    if (L <= 0)
        return false;

    const double anchorTol = 0.5;
    const double pointTol = 3.0;
    const double segmentTol = 2.5;

    auto samePoint = [anchorTol](const QPointF& a, const QPointF& b) {
        return std::abs(a.x() - b.x()) <= anchorTol
            && std::abs(a.y() - b.y()) <= anchorTol;
    };

    bool hasForwardCandidate = false;
    double bestForwardScore = std::numeric_limits<double>::max();
    double bestForwardPointDistance = std::numeric_limits<double>::max();
    QPointF bestForwardAbs;

    bool hasBacktrackCandidate = false;
    double bestBacktrackScore = std::numeric_limits<double>::max();
    double bestBacktrackPointDistance = std::numeric_limits<double>::max();
    QPointF bestBacktrackAbs;

    auto considerShiftedConnection = [&](const QPointF& baseCurrent,
                                         const QPointF& baseOther) {
        const std::int64_t k = static_cast<std::int64_t>(std::llround(
            (currentAbsMM.x() - baseCurrent.x()) / static_cast<double>(L)));
        const QPointF shiftedCurrent(baseCurrent.x() + static_cast<double>(k * L),
                                     baseCurrent.y());
        if (!samePoint(shiftedCurrent, currentAbsMM))
            return;

        const QPointF shiftedCandidate(baseOther.x() + static_cast<double>(k * L),
                                       baseOther.y());
        const QLineF shiftedSegment(currentAbsMM, shiftedCandidate);
        const double segmentDistance = pointDistanceToSegment(clickedDisplayAbsMM,
                                                              shiftedSegment);
        const double pointDistance = QLineF(shiftedCandidate, clickedDisplayAbsMM).length();

        if (segmentDistance > segmentTol && pointDistance > pointTol)
            return;

        const double score = std::min(segmentDistance, pointDistance);
        const bool isBacktrack = previousAbsMM && samePoint(shiftedCandidate, *previousAbsMM);
        bool* hasCandidate = isBacktrack ? &hasBacktrackCandidate : &hasForwardCandidate;
        double* bestScore = isBacktrack ? &bestBacktrackScore : &bestForwardScore;
        double* bestPointDistance = isBacktrack ? &bestBacktrackPointDistance
                                                : &bestForwardPointDistance;
        QPointF* bestAbs = isBacktrack ? &bestBacktrackAbs : &bestForwardAbs;

        if (score < *bestScore
            || (std::abs(score - *bestScore) <= 1e-6
                && pointDistance < *bestPointDistance))
        {
            *bestScore = score;
            *bestPointDistance = pointDistance;
            *bestAbs = shiftedCandidate;
            *hasCandidate = true;
        }
    };

    for (const QLineF& seg : m_sketchSegments)
    {
        considerShiftedConnection(seg.p1(), seg.p2());
        considerShiftedConnection(seg.p2(), seg.p1());
    }

    if (hasForwardCandidate)
    {
        *resolvedAbsMM = bestForwardAbs;
        return true;
    }

    if (hasBacktrackCandidate)
    {
        *resolvedAbsMM = bestBacktrackAbs;
        return true;
    }

    return false;
}

bool WorkspaceView::eraseSketchCoveredBySegment(const QLineF& tracedAbsSegment)
{
    if (m_sketchSegments.empty())
        return false;

    auto sub = [](const QPointF& a, const QPointF& b) {
        return QPointF(a.x() - b.x(), a.y() - b.y());
    };
    auto cross = [](const QPointF& a, const QPointF& b) {
        return a.x() * b.y() - a.y() * b.x();
    };

    const QPointF t1 = tracedAbsSegment.p1();
    const QPointF t2 = tracedAbsSegment.p2();
    const QPointF td = sub(t2, t1);
    const double eps = 0.001;

    if (std::abs(td.x()) < eps && std::abs(td.y()) < eps)
        return false;

    auto coveredByTrace = [&](const QLineF& sketchSeg) {
        const QPointF s1 = sketchSeg.p1();
        const QPointF s2 = sketchSeg.p2();

        const QPointF ts1 = sub(s1, t1);
        const QPointF ts2 = sub(s2, t1);
        if (std::abs(cross(td, ts1)) > eps || std::abs(cross(td, ts2)) > eps)
            return false;

        const bool useX = std::abs(td.x()) >= std::abs(td.y());
        auto proj = [&](const QPointF& p) { return useX ? p.x() : p.y(); };

        double ta = proj(t1);
        double tb = proj(t2);
        if (ta > tb)
            std::swap(ta, tb);

        double sa = proj(s1);
        double sb = proj(s2);
        if (sa > sb)
            std::swap(sa, sb);

        const double overlap = std::min(tb, sb) - std::max(ta, sa);
        return overlap > eps;
    };

    bool removed = false;
    std::vector<QLineF> kept;
    kept.reserve(m_sketchSegments.size());

    for (const QLineF& seg : m_sketchSegments)
    {
        if (coveredByTrace(seg))
            removed = true;
        else
            kept.push_back(seg);
    }

    if (!removed)
        return false;

    pushSketchUndoSnapshot();
    m_sketchSegments = std::move(kept);
    rebuildSketchPointsFromSegments();
    clearSketchSelection();

    if (viewport())
        viewport()->update();

    return true;
}

