void WorkspaceView::stopAnimation()
{
    if (!m_anim || !m_scene)
        return;

    m_anim->stop();
    m_scene->setAnimationState(false, 0, 1.0);
    if (viewport())
        viewport()->update();
}

bool WorkspaceView::isAnimating() const
{
    return m_anim && m_anim->running();
}

// ============================================================
// Transform UNIQUE
// ============================================================

void WorkspaceView::zoomInView()
{
    const double nextZoom = std::min(VIEW_ZOOM_MAX, m_zoomFactor * VIEW_ZOOM_STEP);
    if (std::abs(nextZoom - m_zoomFactor) < 1e-6)
        return;

    m_zoomFactor = nextZoom;
    updateViewTransform();
    if (viewport())
        viewport()->update();
}

void WorkspaceView::zoomOutView()
{
    const double nextZoom = std::max(VIEW_ZOOM_MIN, m_zoomFactor / VIEW_ZOOM_STEP);
    if (std::abs(nextZoom - m_zoomFactor) < 1e-6)
        return;

    m_zoomFactor = nextZoom;
    updateViewTransform();
    if (viewport())
        viewport()->update();
}

void WorkspaceView::zoomResetView()
{
    if (std::abs(m_zoomFactor - 1.0) < 1e-6)
        return;

    m_zoomFactor = 1.0;
    updateViewTransform();
    if (viewport())
        viewport()->update();
}

void WorkspaceView::applyHome()
{
    updateViewTransform();
}

void WorkspaceView::updateViewTransform()
{
    const int offsetMM = m_model ? m_model->ribbonOffsetMM() : 0;

    QTransform t;
    t.translate(JONCTION_MARGIN_PX, BLUE_RULE_HEIGHT_PX);
    t.scale(MM_TO_PX * m_zoomFactor, MM_TO_PX * m_zoomFactor);
    t.translate(-static_cast<double>(offsetMM), 0.0);

    setTransform(t);
}

